// Dumb transport: one Telegram message -> one immutable markdown file.
// A message that STARTS with a control verb (status/next/go/run/build/review/stop/enable/disable) is
// a remote-control command -> captures/commands/. A message that STARTS with a decision verb
// (approve/park/reject/clarify) is an approval reply -> captures/decisions/. Everything else is a
// capture -> captures/inbox/. No AI, no parsing of planning files here -- Dispatch-Commands.ps1,
// Apply-Decisions.ps1, and the Claude triage run do all the logic, on the PC.
const msg = ($input.first().json.message) || {};
const text = (msg.text || '').trim();
const d = new Date();
const p = (n) => String(n).padStart(2, '0');
const ts = `${d.getUTCFullYear()}${p(d.getUTCMonth()+1)}${p(d.getUTCDate())}T${p(d.getUTCHours())}${p(d.getUTCMinutes())}Z`;
const msgId = msg.message_id || 'na';
const controlMatch = text.match(/^\/(status|next|go|run|build|review|stop|enable|disable)\b/i);
const isControl = !!controlMatch;
const isDecision = !isControl && /^\s*(approve|park|reject|clarify)\b/i.test(text);
let id, path, command, content;
if (isControl) {
  const ctrl = controlMatch[1].toLowerCase();
  id = `${ts}-${msgId}-command`;
  path = `captures/commands/${id}.md`;
  command = ctrl;
  content = `---\nid: ${id}\nkind: command\ncommand: ${ctrl}\ncaptured: ${d.toISOString()}\nvia: telegram\nmsg_id: ${msgId}\nstatus: new\n---\n\n${text}\n`;
} else if (isDecision) {
  id = `${ts}-${msgId}-decide`;
  path = `captures/decisions/${id}.md`;
  command = 'decide';
  content = `---\nid: ${id}\nkind: decision\ncaptured: ${d.toISOString()}\nvia: telegram\nmsg_id: ${msgId}\nstatus: new\n---\n\n${text || '(empty)'}\n`;
} else {
  const m = text.match(/^\/(feature|bug|idea|research|todo)\b\s*([\s\S]*)$/i);
  const type = m ? m[1].toLowerCase() : 'unknown';
  command = m ? ('/' + type) : '(none)';
  const body = (m ? (m[2] || '') : text).trim();
  id = `${ts}-${msgId}-${type}`;
  path = `captures/inbox/${id}.md`;
  content = `---\nid: ${id}\ncommand: ${command}\ntype: ${type}\ncaptured: ${d.toISOString()}\nvia: telegram\nmsg_id: ${msgId}\nstatus: new\n---\n\n${body || '(empty capture)'}\n`;
}
const contentB64 = Buffer.from(content, 'utf8').toString('base64');
return [{ json: { id, path, command, isControl, isDecision, contentB64, chatId: (msg.chat && msg.chat.id) } }];
